import React, { useState } from "react";
import axios from "axios";
import Table from "react-bootstrap/Table";
import Button from "react-bootstrap/Button";
import Form from "react-bootstrap/Form";

const FileUpload = () => {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState([]);
  const [message, setMessage] = useState("");
  const [mappings, setMappings] = useState({});

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!file) {
      setMessage("Please select a file first!");
      return;
    }

    try {
      const formData = new FormData();
      formData.append("file", file);

      const token = localStorage.getItem("token"); // from login
      const res = await axios.post(
        "http://localhost:4000/api/upload/upload",
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
            Authorization: `Bearer ${token}`,
            //Authorization: `Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY5OTllMzk3ZGU0NmQ4ZWYxNGE2MzMyOCIsInJvbGUiOiJhZG1pbiIsImlhdCI6MTc3MTg1ODAyMSwiZXhwIjoxNzcxOTQ0NDIxfQ.MD_q9579iM-tm-RKmuuGY1_J3ZB5XZiEEbRAhItt6cg',
          },
        }
      );

      setPreview(res.data.preview);
      setMessage(res.data.message);
    } catch (err) {
      console.error(err);
      setMessage("Upload failed!");
    }
  };

  const handleMappingChange = (columnName, systemField) => {
    setMappings({ ...mappings, [columnName]: systemField });
  };

  const systemFields = [
    "Transaction ID",
    "Amount",
    "Reference Number",
    "Date",
  ];

  return (
    <div className="container mt-5">
      <h2>📤 File Upload & Column Mapping</h2>
      <div className="mb-3">
        <input type="file" onChange={handleFileChange} className="form-control" />
      </div>
      <Button onClick={handleUpload} variant="primary">
        Upload File
      </Button>
      
      {message && <p className="mt-3">{message}</p>}

      {preview.length > 0 && (
        <div className="mt-4">
          <h4>🧾 Preview (First 20 Rows)</h4>
          <Table striped bordered hover size="sm">
            <thead>
              <tr>
                {Object.keys(preview[0]).map((col) => (
                  <th key={col}>
                    {col}
                    <Form.Select
                      size="sm"
                      className="mt-1"
                      onChange={(e) => handleMappingChange(col, e.target.value)}
                      value={mappings[col] || ""}
                    >
                      <option value="">-- Map to --</option>
                      {systemFields.map((field) => (
                        <option key={field} value={field}>
                          {field}
                        </option>
                      ))}
                    </Form.Select>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {preview.map((row, idx) => (
                <tr key={idx}>
                  {Object.values(row).map((val, i) => (
                    <td key={i}>{val}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </Table>
        </div>
      )}

      {Object.keys(mappings).length > 0 && (
        <div className="mt-3">
          <h5>✅ Current Mappings</h5>
          <pre>{JSON.stringify(mappings, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default FileUpload;
